"""π_θ-opponent ensemble (self-contained). Rollout opponent = fast
numpy policy distilled from bovard 1500+; candidates = real v4 + marco."""
import base64 as _b64
import io as _io
import math
import time

import numpy as np

_V4_B64 = ""
_MARCO_B64 = ""
_PI_W_B64 = ""


def _exec_src(b64):
    ns = {}
    exec(compile(_b64.b64decode(b64).decode(), "<embedded>", "exec"), ns)
    return ns


_V4_REAL = _exec_src(_V4_B64)
_MARCO_REAL = _exec_src(_MARCO_B64)


def _v4_real_agent(obs):
    try:
        r = _V4_REAL["agent"](obs)
        return list(r) if r else []
    except Exception:
        return []


def _marco_real_agent(obs, config=None):
    try:
        r = _MARCO_REAL["agent"](obs, config)
        return list(r) if r else []
    except Exception:
        return []


class _AttrDict(dict):
    def __getattr__(self, k):
        try:
            return self[k]
        except KeyError as e:
            raise AttributeError(k) from e


# ---------------------- fast_sim (inlined) ----------------------

import copy
import math

BOARD_SIZE = 100.0
CENTER = 50.0
SUN_RADIUS = 10.0
ROTATION_RADIUS_LIMIT = 50.0


def _distance(ax, ay, bx, by):
    return math.sqrt((ax - bx) ** 2 + (ay - by) ** 2)


def _point_to_segment_distance(px, py, vx, vy, wx, wy):
    l2 = (vx - wx) ** 2 + (vy - wy) ** 2
    if l2 == 0.0:
        return _distance(px, py, vx, vy)
    t = max(0.0, min(1.0, ((px - vx) * (wx - vx) + (py - vy) * (wy - vy)) / l2))
    projx = vx + t * (wx - vx)
    projy = vy + t * (wy - vy)
    return _distance(px, py, projx, projy)


def new_state(obs, *, ship_speed=6.0, episode_steps=500):
    """Build a sim state from an agent observation (dict or namespace)."""
    def g(key, default):
        if isinstance(obs, dict):
            return obs.get(key, default)
        return getattr(obs, key, default)

    return {
        "planets": [list(p) for p in g("planets", [])],
        "fleets": [list(f) for f in g("fleets", [])],
        "initial_planets": [list(p) for p in g("initial_planets", [])],
        "comets": copy.deepcopy(g("comets", [])),
        "comet_planet_ids": list(g("comet_planet_ids", [])),
        "next_fleet_id": g("next_fleet_id", 0),
        "angular_velocity": g("angular_velocity", 0.0),
        "step": g("step", 0),
        "ship_speed": ship_speed,
        "episode_steps": episode_steps,
    }


def clone(state):
    return {
        "planets": [p[:] for p in state["planets"]],
        "fleets": [f[:] for f in state["fleets"]],
        "initial_planets": [p[:] for p in state["initial_planets"]],
        "comets": copy.deepcopy(state["comets"]),
        "comet_planet_ids": list(state["comet_planet_ids"]),
        "next_fleet_id": state["next_fleet_id"],
        "angular_velocity": state["angular_velocity"],
        "step": state["step"],
        "ship_speed": state["ship_speed"],
        "episode_steps": state["episode_steps"],
    }


def step(state, joint_actions, num_agents):
    """Advance one turn. joint_actions: list[num_agents] of move lists.

    Each move = [from_planet_id, angle, ships]. Mutates & returns state.
    Adds state['_done'] and state['_scores'] when terminated.
    """
    planets = state["planets"]
    fleets = state["fleets"]
    av = state["angular_velocity"]
    step_no = state["step"]

    # --- 0a. Remove expired comets before fleet launch (engine 419-439) ---
    expired = []
    for group in state["comets"]:
        idx = group["path_index"]
        for i, pid in enumerate(group["planet_ids"]):
            if idx >= len(group["paths"][i]):
                expired.append(pid)
    if expired:
        eset = set(expired)
        state["planets"] = planets = [p for p in planets if p[0] not in eset]
        state["initial_planets"] = [
            p for p in state["initial_planets"] if p[0] not in eset
        ]
        state["comet_planet_ids"] = [
            pid for pid in state["comet_planet_ids"] if pid not in eset
        ]
        for group in state["comets"]:
            group["planet_ids"] = [
                pid for pid in group["planet_ids"] if pid not in eset
            ]
        state["comets"] = [g for g in state["comets"] if g["planet_ids"]]

    # --- 0b. Comet spawning: SKIPPED (cannot predict random ship count) ---

    # --- 1. Fleet launch (engine 480-512) ---
    pmap = {p[0]: p for p in planets}
    for pid in range(num_agents):
        action = joint_actions[pid] if pid < len(joint_actions) else None
        if not action or not isinstance(action, list):
            continue
        for move in action:
            if len(move) != 3:
                continue
            from_id, angle, ships = move
            ships = int(ships)
            fp = pmap.get(from_id)
            if fp is not None and fp[1] == pid:
                if fp[5] >= ships and ships > 0:
                    fp[5] -= ships
                    sx = fp[2] + math.cos(angle) * (fp[4] + 0.1)
                    sy = fp[3] + math.sin(angle) * (fp[4] + 0.1)
                    fleets.append(
                        [state["next_fleet_id"], pid, sx, sy, angle, from_id, ships]
                    )
                    state["next_fleet_id"] += 1

    # --- 2. Production (engine 514-517) ---
    for p in planets:
        if p[1] != -1:
            p[5] += p[6]

    # --- 3. Fleet movement + continuous collision (engine 519-551) ---
    max_speed = state["ship_speed"]
    to_remove_idx = set()
    combat = {p[0]: [] for p in planets}
    for fi, fleet in enumerate(fleets):
        angle = fleet[4]
        ships = fleet[6]
        speed = 1.0 + (max_speed - 1.0) * (math.log(ships) / math.log(1000)) ** 1.5
        speed = min(speed, max_speed)
        ox, oy = fleet[2], fleet[3]
        fleet[2] += math.cos(angle) * speed
        fleet[3] += math.sin(angle) * speed
        nx, ny = fleet[2], fleet[3]
        if not (0 <= nx <= BOARD_SIZE and 0 <= ny <= BOARD_SIZE):
            to_remove_idx.add(fi)
            continue
        if _point_to_segment_distance(CENTER, CENTER, ox, oy, nx, ny) < SUN_RADIUS:
            to_remove_idx.add(fi)
            continue
        for p in planets:
            if _point_to_segment_distance(p[2], p[3], ox, oy, nx, ny) < p[4]:
                combat[p[0]].append(fleet)
                to_remove_idx.add(fi)
                break

    # --- 4. Planet rotation + sweep (engine 553-610) ---
    comet_pids = set(state["comet_planet_ids"])
    init_by_id = {p[0]: p for p in state["initial_planets"]}

    def sweep(planet, ox, oy, nx, ny):
        if ox == nx and oy == ny:
            return
        for fi, fleet in enumerate(fleets):
            if fi in to_remove_idx:
                continue
            if _point_to_segment_distance(fleet[2], fleet[3], ox, oy, nx, ny) < planet[4]:
                combat[planet[0]].append(fleet)
                to_remove_idx.add(fi)

    for planet in planets:
        if planet[0] in comet_pids:
            continue
        ip = init_by_id.get(planet[0])
        if not ip:
            continue
        dx = ip[2] - CENTER
        dy = ip[3] - CENTER
        r = math.sqrt(dx * dx + dy * dy)
        ox, oy = planet[2], planet[3]
        if r + planet[4] < ROTATION_RADIUS_LIMIT:
            ia = math.atan2(dy, dx)
            ca = ia + av * step_no
            planet[2] = CENTER + r * math.cos(ca)
            planet[3] = CENTER + r * math.sin(ca)
        sweep(planet, ox, oy, planet[2], planet[3])

    # Comet movement (engine 592-610)
    expired2 = []
    for group in state["comets"]:
        group["path_index"] += 1
        idx = group["path_index"]
        for i, pid in enumerate(group["planet_ids"]):
            planet = pmap.get(pid)
            if planet is None:
                continue
            ppath = group["paths"][i]
            if idx >= len(ppath):
                expired2.append(pid)
            else:
                ox, oy = planet[2], planet[3]
                planet[2] = ppath[idx][0]
                planet[3] = ppath[idx][1]
                if ox >= 0:
                    sweep(planet, ox, oy, planet[2], planet[3])

    if expired2:
        eset = set(expired2)
        state["planets"] = planets = [p for p in planets if p[0] not in eset]
        state["initial_planets"] = [
            p for p in state["initial_planets"] if p[0] not in eset
        ]
        state["comet_planet_ids"] = [
            pid for pid in state["comet_planet_ids"] if pid not in eset
        ]
        for group in state["comets"]:
            group["planet_ids"] = [
                pid for pid in group["planet_ids"] if pid not in eset
            ]
        state["comets"] = [g for g in state["comets"] if g["planet_ids"]]
        combat = {k: v for k, v in combat.items() if k not in eset}

    state["fleets"] = [f for i, f in enumerate(fleets) if i not in to_remove_idx]

    # --- 5. Combat resolution (engine 630-669) ---
    pmap = {p[0]: p for p in state["planets"]}
    for pid, pf in combat.items():
        planet = pmap.get(pid)
        if not planet or not pf:
            continue
        player_ships = {}
        for fleet in pf:
            player_ships[fleet[1]] = player_ships.get(fleet[1], 0) + fleet[6]
        if not player_ships:
            continue
        sp = sorted(player_ships.items(), key=lambda kv: kv[1], reverse=True)
        top_player, top_ships = sp[0]
        if len(sp) > 1:
            second = sp[1][1]
            surv = top_ships - second
            if sp[0][1] == sp[1][1]:
                surv = 0
            surv_owner = top_player if surv > 0 else -1
        else:
            surv_owner = top_player
            surv = top_ships
        if surv > 0:
            if planet[1] == surv_owner:
                planet[5] += surv
            else:
                planet[5] -= surv
                if planet[5] < 0:
                    planet[1] = surv_owner
                    planet[5] = abs(planet[5])

    # --- 6. Termination + scoring (engine 678-711) ---
    state["step"] = step_no + 1
    terminated = False
    if state["step"] >= state["episode_steps"] - 2:
        terminated = True
    alive = set()
    for p in state["planets"]:
        if p[1] != -1:
            alive.add(p[1])
    for f in state["fleets"]:
        alive.add(f[1])
    if len(alive) <= 1:
        terminated = True

    state["_done"] = terminated
    if terminated:
        scores = [0] * num_agents
        for p in state["planets"]:
            if p[1] != -1 and p[1] < num_agents:
                scores[p[1]] += p[5]
        for f in state["fleets"]:
            if f[1] < num_agents:
                scores[f[1]] += f[6]
        state["_scores"] = scores
        mx = max(scores) if scores else 0
        state["_rewards"] = [
            1 if (s == mx and mx > 0) else -1 for s in scores
        ]
    return state


# ---------------------- encode_state (inlined, parity-tested) ----------------------
MAXP = 48                       # 20-40 planets + ≤4 transient comets, padded
F = 15                          # per-planet feature dim
G = 8                           # global feature dim
_PID, _OWN, _X, _Y, _R, _SHIPS, _PROD = range(7)
CENTER = 50.0
ROT_LIMIT = 50.0
_COMET_STEPS = (50, 150, 250, 350, 450)


def _ang(px, py, qx, qy):
    return math.atan2(qy - py, qx - px)


def _adiff(a, b):
    d = (a - b) % (2 * math.pi)
    return min(d, 2 * math.pi - d)


def encode_state(obs, player):
    """obs dict/namespace → (pf[MAXP,F], pmask[MAXP], omask[MAXP], gf[G],
    planet_ids[list]). planet_ids maps row→engine planet id (for decoding
    a target row back to a move at inference)."""
    g = (obs.get if isinstance(obs, dict)
         else lambda k, d=None: getattr(obs, k, d))
    planets = list(g("planets", []) or [])[:MAXP]
    fleets = list(g("fleets", []) or [])
    comet_ids = set(g("comet_planet_ids", []) or [])
    step = int(g("step", 0) or 0)
    np_agents = 4 if any(
        int(p[_OWN]) >= 2 for p in planets if int(p[_OWN]) >= 0
    ) else 2

    n = len(planets)
    pf = np.zeros((MAXP, F), np.float32)
    pmask = np.zeros(MAXP, np.float32)
    omask = np.zeros(MAXP, np.float32)
    planet_ids = [-1] * MAXP

    # incoming fleet pressure per planet (by relation to `player`)
    press_mine = [0.0] * n
    press_enemy = [0.0] * n
    for f in fleets:
        fa = f[4]
        fx, fy = f[2], f[3]
        best_j, best_e = -1, 1e9
        for j, p in enumerate(planets):
            e = _adiff(fa, _ang(fx, fy, p[_X], p[_Y]))
            if e < best_e:
                best_e, best_j = e, j
        if best_j >= 0 and best_e < 0.5:
            if int(f[1]) == player:
                press_mine[best_j] += f[6]
            elif int(f[1]) >= 0:
                press_enemy[best_j] += f[6]

    my_tot = opp_tot = neu_tot = 0.0
    my_np = 0
    for i, p in enumerate(planets):
        own = int(p[_OWN])
        ships = float(p[_SHIPS])
        if own == player:
            my_tot += ships + p[_PROD] * 8
            my_np += 1
        elif own == -1:
            neu_tot += ships
        else:
            opp_tot += ships + p[_PROD] * 8
        dx, dy = p[_X] - CENTER, p[_Y] - CENTER
        dsun = math.hypot(dx, dy)
        is_orb = 1.0 if (dsun + p[_R] < ROT_LIMIT) else 0.0
        pf[i] = (
            1.0 if own == player else 0.0,
            1.0 if (own >= 0 and own != player) else 0.0,
            1.0 if own == -1 else 0.0,
            math.log1p(ships) / 8.0,
            p[_PROD] / 5.0,
            p[_R] / 4.0,
            p[_X] / 100.0,
            p[_Y] / 100.0,
            dsun / 70.0,
            1.0 if p[_PID] in comet_ids else 0.0,
            is_orb,
            math.log1p(press_mine[i]) / 8.0,
            math.log1p(press_enemy[i]) / 8.0,
            1.0 if own == player else 0.0,
            1.0,
        )
        pmask[i] = 1.0
        planet_ids[i] = int(p[_PID])
        if own == player:
            omask[i] = 1.0

    nxt = next((c for c in _COMET_STEPS if c > step), 500)
    sc = 200.0
    gf = np.array([
        step / 500.0,
        1.0 if np_agents == 4 else 0.0,
        my_tot / sc, opp_tot / sc, neu_tot / sc,
        my_np / 20.0,
        (nxt - step) / 100.0,
        my_np / max(1, n),
    ], np.float32)
    return pf, pmask, omask, gf, planet_ids


def _sym(planets, fleets, mode):
    """4-fold board mirror (Orbit Wars symmetry; 2nd-place-Lux transfer).
    mode 0=id, 1=mirror-x, 2=mirror-y, 3=180°. Planet LIST ORDER kept →
    target-index / launch / ship_frac labels stay valid (move angle is
    re-derived from geometry at decode time, so it's not stored)."""
    if mode == 0:
        return planets, fleets
    fx = mode in (1, 3)        # flip x
    fy = mode in (2, 3)        # flip y
    P = []
    for p in planets:
        q = list(p)
        if fx:
            q[2] = 100.0 - q[2]
        if fy:
            q[3] = 100.0 - q[3]
        P.append(q)
    Fl = []
    for f in fleets:
        q = list(f)
        if fx:
            q[2] = 100.0 - q[2]
        if fy:
            q[3] = 100.0 - q[3]
        a = q[4]
        if fx:
            a = math.pi - a
        if fy:
            a = -a
        q[4] = math.atan2(math.sin(a), math.cos(a))
        Fl.append(q)
    return P, Fl



# ---------------------- pi_theta numpy weights ----------------------
_z = np.load(_io.BytesIO(_b64.b64decode(_PI_W_B64)))
_W = {k: _z[k].astype(np.float32) for k in _z.files if not k.startswith("_")}
_META = (int(_z["_F"]), int(_z["_G"]), int(_z["_D"]))


def load(*a, **k):  # decode_moves guard no-op (weights already loaded)
    return _W, _META


# ---------------------- pi_theta numpy forward (inlined, parity-tested) ----------
def _ln(x, w, b, eps=1e-5):
    m = x.mean(-1, keepdims=True)
    v = x.var(-1, keepdims=True)            # biased (torch LayerNorm)
    return (x - m) / np.sqrt(v + eps) * w + b


def _lin(x, w, b):
    return x @ w.T + b


def _softmax(x):
    x = x - x.max(-1, keepdims=True)
    e = np.exp(x)
    return e / e.sum(-1, keepdims=True)


def _mha(h, w, pfx, kpm, heads=4):
    # torch nn.MultiheadAttention(batch_first=True), packed in_proj.
    S, D = h.shape
    dh = D // heads
    ipw = w[f"{pfx}.in_proj_weight"]
    ipb = w[f"{pfx}.in_proj_bias"]
    q = h @ ipw[:D].T + ipb[:D]
    k = h @ ipw[D:2 * D].T + ipb[D:2 * D]
    v = h @ ipw[2 * D:].T + ipb[2 * D:]
    q = q.reshape(S, heads, dh).transpose(1, 0, 2)        # [H,S,dh]
    k = k.reshape(S, heads, dh).transpose(1, 0, 2)
    v = v.reshape(S, heads, dh).transpose(1, 0, 2)
    sc = (q @ k.transpose(0, 2, 1)) / np.sqrt(dh)         # [H,S,S]
    sc = np.where(kpm[None, None, :], -np.inf, sc)        # mask pad keys
    a = _softmax(sc) @ v                                  # [H,S,dh]
    a = a.transpose(1, 0, 2).reshape(S, D)
    return _lin(a, w[f"{pfx}.out_proj.weight"], w[f"{pfx}.out_proj.bias"])


def forward(pf, pmask, gf):
    """pf[P,F] pmask[P] gf[G] → gate[P], tgt[P,P], frac[P]."""
    w = _W
    x = _lin(pf, w["inp.weight"], w["inp.bias"]) + _lin(
        gf, w["gemb.weight"], w["gemb.bias"])
    kpm = pmask < 0.5
    for bi in (0, 1):
        p = f"blocks.{bi}"
        h = _ln(x, w[f"{p}.n1.weight"], w[f"{p}.n1.bias"])
        x = x + _mha(h, w, f"{p}.att", kpm)
        h2 = _ln(x, w[f"{p}.n2.weight"], w[f"{p}.n2.bias"])
        ff = np.maximum(0.0, _lin(h2, w[f"{p}.ff.0.weight"],
                                  w[f"{p}.ff.0.bias"]))
        x = x + _lin(ff, w[f"{p}.ff.2.weight"], w[f"{p}.ff.2.bias"])
    gh = np.maximum(0.0, _lin(x, w["gate.0.weight"], w["gate.0.bias"]))
    gate = _lin(gh, w["gate.2.weight"], w["gate.2.bias"]).squeeze(-1)
    fh = np.maximum(0.0, _lin(x, w["frac.0.weight"], w["frac.0.bias"]))
    frac = 1.0 / (1.0 + np.exp(
        -_lin(fh, w["frac.2.weight"], w["frac.2.bias"]).squeeze(-1)))
    q = _lin(x, w["tq.weight"], w["tq.bias"])
    k = _lin(x, w["tk.weight"], w["tk.bias"])
    D = q.shape[-1]
    tgt = (q @ k.T) / np.sqrt(D)
    tgt[:, kpm] = -np.inf
    np.fill_diagonal(tgt, -np.inf)
    return gate, tgt, frac


def decode_moves(obs, player, gate_thr=0.0):
    """π_θ's joint move for `player` at `obs` (rollout-opponent use)."""
    if _W is None:
        load()
    pf, pmask, omask, gf, pids = encode_state(obs, player)
    gate, tgt, frac = forward(pf, pmask, gf)
    planets = obs["planets"] if isinstance(obs, dict) else obs.planets
    pos = {int(p[0]): (p[2], p[3]) for p in planets}
    ships_of = {int(p[0]): p[5] for p in planets}
    moves = []
    import math
    for r in np.where(omask > 0.5)[0]:
        if gate[r] <= gate_thr:
            continue
        tr = int(np.argmax(tgt[r]))
        sid, tid = pids[r], pids[tr]
        if sid < 0 or tid < 0:
            continue
        n = int(round(frac[r] * ships_of.get(sid, 0)))
        if n <= 0:
            continue
        sx, sy = pos[sid]
        tx, ty = pos[tid]
        moves.append([sid, math.atan2(ty - sy, tx - sx), n])
    return moves




# ---------------------- ensemble logic ----------------------
TIME_BUDGET_S = 0.80
ROLLOUT_DEPTH = 400  # π_θ ~1ms/step → deadline (not depth) is the cap


def _read(obs, k, d=None):
    if isinstance(obs, dict):
        return obs.get(k, d)
    return getattr(obs, k, d)


def _opp_view(state, player):
    return {
        "player": player,
        "planets": [list(p) for p in state["planets"]],
        "fleets": [list(f) for f in state["fleets"]],
        "initial_planets": [list(p) for p in state["initial_planets"]],
        "comets": state["comets"],
        "comet_planet_ids": list(state["comet_planet_ids"]),
        "angular_velocity": state["angular_velocity"],
        "next_fleet_id": state["next_fleet_id"],
        "step": state["step"],
    }


def _score_for(state, me, num_agents):
    if state.get("_done"):
        rew = state.get("_rewards")
        if rew and me < len(rew):
            return 1e6 if rew[me] == 1 else -1e6
    my = opp = 0.0
    for p in state["planets"]:
        v = p[5] + p[6] * 8.0
        if p[1] == me:
            my += v
        elif p[1] >= 0:
            opp += v
    for f in state["fleets"]:
        if f[1] == me:
            my += f[6]
        elif f[1] >= 0:
            opp += f[6]
    return my - opp


def _pi_move(view, p):
    try:
        return decode_moves(view, p)
    except Exception:
        return []


def _rollout(state, me, num_agents, first_move, depth, deadline):
    s = clone(state)
    acts = [first_move if p == me else _pi_move(_opp_view(s, p), p)
            for p in range(num_agents)]
    step(s, acts, num_agents)
    for _ in range(depth - 1):
        if s.get("_done") or time.perf_counter() > deadline:
            break
        acts = [_pi_move(_opp_view(s, p), p) for p in range(num_agents)]
        step(s, acts, num_agents)
    return _score_for(s, me, num_agents)


def agent(obs, config=None):
    t0 = time.perf_counter()
    deadline = t0 + TIME_BUDGET_S
    me = int(_read(obs, "player", 0))
    planets = _read(obs, "planets", []) or []
    owners = {int(p[1]) for p in planets if int(p[1]) >= 0}
    num_agents = 4 if (owners and max(owners) >= 2) else 2

    v4_move = _v4_real_agent(obs)
    marco_move = _marco_real_agent(obs, config)
    if not marco_move or marco_move == v4_move:
        return v4_move

    state = new_state(obs)
    now = time.perf_counter()
    per = max(0.0, (deadline - now) / 2.0)
    s_v4 = _rollout(state, me, num_agents, v4_move, ROLLOUT_DEPTH, now + per)
    now2 = time.perf_counter()
    s_marco = _rollout(state, me, num_agents, marco_move,
                       ROLLOUT_DEPTH, now2 + per)

    margin = max(10.0, 0.05 * abs(s_v4))
    if s_marco > s_v4 + margin:
        return marco_move
    return v4_move


__all__ = ["agent"]
